{
	// create a graph of 8 vertices
	Graph g(8);
	// add edges to it
    g.addEdge(0, 1);	/*    0  ----------   2          */
    g.addEdge(0, 2);	/*      \          /  |  \       */
    g.addEdge(1, 4);	/*        1 --- 4 --- 3    6     */
