public class TopologicalSortHarness {
    public static int[] topologicalSort(Map<Integer, List<Integer>> adjacencyList) {
        int n = 0;
        for (Map.Entry<Integer, List<Integer>> entry : adjacencyList.entrySet()) {
            n = Math.max(n, entry.getKey() + 1);
            for (int next : entry.getValue()) {
                n = Math.max(n, next + 1);
            }
        }

        int[] indegree = new int[n];
        for (List<Integer> neighbors : adjacencyList.values()) {
            for (int next : neighbors) {
                indegree[next]++;
            }
        }

        PriorityQueue<Integer> ready = new PriorityQueue<>();
        for (int i = 0; i < n; i++) {
            if (indegree[i] == 0) {
                ready.add(i);
            }
        }

        List<Integer> order = new ArrayList<>();
        while (!ready.isEmpty()) {
            int node = ready.poll();
            order.add(node);
            for (int next : adjacencyList.getOrDefault(node, java.util.Collections.emptyList())) {
                indegree[next]--;
                if (indegree[next] == 0) {
                    ready.add(next);
                }
            }
        }

        int[] result = new int[order.size()];
        for (int i = 0; i < order.size(); i++) {
            result[i] = order.get(i);
        }
        return result;
    }
}

import java.util.PriorityQueue

/**
 * Topological sort of a directed acyclic graph.
 * Returns the lexicographically smallest valid order to keep tests deterministic.
 */
fun topologicalSort(adjList: Map<Int, List<Int>>): List<Int> {
    val nodeCount = adjList.size
    val inDegree = IntArray(nodeCount)

    for (neighbors in adjList.values) {
        for (neighbor in neighbors) {
            if (neighbor in 0 until nodeCount) {
                inDegree[neighbor]++
            }
        }
    }

    val available = PriorityQueue<Int>()
    for (node in 0 until nodeCount) {
        if (inDegree[node] == 0) {
            available.add(node)
        }
    }

    val order = mutableListOf<Int>()
    while (available.isNotEmpty()) {
        val node = available.poll()
        order.add(node)

        for (neighbor in adjList[node] ?: emptyList()) {
            if (neighbor !in 0 until nodeCount) {
                continue
            }
            inDegree[neighbor]--
            if (inDegree[neighbor] == 0) {
                available.add(neighbor)
            }
        }
    }

    return order
}

